SELECT COUNT(DISTINCT PB.PK) AS QUANTIDADE FROM LATTES_P_PRODBIB PP JOIN LATTES_PRODBIB PB ON PB.PK = PP.FK_PRODBIB JOIN SERVIDOR S ON S.PK_SIAPE = PP.FK_SIAPE WHERE LOWER(PB.TIPO) = LOWER('trabalho em evento') AND LOWER(PB.NATUREZA) = LOWER('completo') AND PB.ANO = '2020' AND LOWER(S.SIGLA_CAMPUS) = LOWER('jat') AND LOWER(COALESCE(S.AREA_INGRESSO, '')) = 'engenharia civil'